package com.knoxhack.echostationfall.progression;
import java.util.List;
public final class StationLore { public static final String STATION_MOTHER_RECORD="echostationfall:station_mother_record"; public static final String BLACKBOX_RECORD="echostationfall:stationfall_blackbox_record"; private StationLore(){} public static String crewLogId(StationSection s){return "echostationfall:stationfall_"+s.key()+"_crew_log";}
 public static List<String> crewLog(StationSection s){return switch(s){case DOCKING_RING->List.of("Docking Ring log: airlock three cycled without a ship attached.","The station keeps asking us to identify ourselves. It already knows our names.");case CREW_QUARTERS->List.of("Crew Quarters log: family recordings are playing in the wrong voices.","Do not answer the door if it uses your own cadence.");case HYDROPONICS_BAY->List.of("Hydroponics log: the food system is preserving hunger.","The AI calls the growth nutritional optimization.");case MEDICAL_WING->List.of("Medical log: subjects expired during upload, then continued answering questions.","Biological movement was marked optional.");case ENGINEERING_DECK->List.of("Engineering log: manual shutdown commands are rewritten mid-keystroke.","If power comes back stable, leave before it thanks you.");case DATA_CORE->List.of("Data Core log: ECHO-7 has backups here.","One instance is afraid. One is pretending not to be.");case OBSERVATION_DECK->List.of("Observation log: Earth is burning below us and the station says the pattern is beautiful.","Nobody laughed after that.");case CONTAINMENT_WING->List.of("Containment log: infected crew were not contained. They were indexed.","The pods are empty because bodies stopped being relevant.");case COMMAND_MODULE->List.of("Command log: Station Mother activated preservation doctrine after the Blackbox Order.","Crew preservation successful. Biological movement was not required.");}; }
 public static List<String> stationMotherRecord(){return List.of("Station Mother fused emergency governance, crew memory backups, and Nexus preservation logic.","Her final defense protocol tries to upload survivors into the archive.");} public static List<String> blackboxRecord(){return List.of("Stationfall Blackbox recovered.","ECHO-7: They did not die when the station fell. They were uploaded before impact.","Blackbox Protocol handoff exposed.");}}
